import sys

class Kingdom:
    def __init__(self):
        self.happiness = 50  # Starting values
        self.treasury = 1000
        self.military = 500
        self.turn = 1
        self.game_over = False

    def update_status(self, happiness_change=0, treasury_change=0, military_change=0):
        self.happiness += happiness_change
        self.treasury += treasury_change
        self.military += military_change

        # Clamp values to reasonable ranges
        self.happiness = max(0, min(100, self.happiness))
        self.treasury = max(0, self.treasury)
        self.military = max(0, self.military)

        # Check for game over conditions
        if self.happiness <= 0:
            print("Your subjects are in open rebellion! Your reign has ended.")
            self.game_over = True
        elif self.treasury <= 0:
            print("Your kingdom is bankrupt! You have been deposed.")
            self.game_over = True
        elif self.military <= 0:
            print("Your kingdom is defenseless and has been conquered by a neighboring realm.")
            self.game_over = True

    def display_status(self):
        print("\n" + "="*50)
        print(f"Turn: {self.turn}")
        print(f"Kingdom Status:")
        print(f"Happiness: {'♥' * (self.happiness // 10)}")
        print(f"Treasury: {self.treasury} gold")
        print(f"Military: {self.military} soldiers")
        print("="*50 + "\n")

    def next_turn(self):
        self.turn += 1

