def slow_print(text, delay=0.03):
    """Print text with a slight delay between characters for a more dramatic effect."""
    for char in text:
        sys.stdout.write(char)
        sys.stdout.flush()
        time.sleep(delay)
    print()

def main():
    # Introduction
    slow_print("\n" + "*"*70)
    slow_print("*                    THE KING'S COURT                           *")
    slow_print("*                   A Kingdom Simulator                         *")
    slow_print("*"*70 + "\n")

    slow_print("As the monarch of your realm, you must make wise decisions to ensure")
    slow_print("the prosperity and security of your kingdom. Each day, you will hear")
    slow_print("petitions from various subjects and must decide how to respond.")
    slow_print("Your choices will affect your kingdom's happiness, treasury, and military strength.")
    slow_print("Rule wisely, Your Majesty!\n")

    input("Press Enter to begin your reign... ")

    # Initialize kingdom
    kingdom = Kingdom()
    visitors = get_visitors()

    # Main game loop
    while not kingdom.game_over and kingdom.turn <= 20:  # Limit to 20 turns for this demo
        kingdom.display_status()

        # Select a random visitor
        visitor = random.choice(visitors)
        visitors.remove(visitor)  # Remove to avoid repetition

        # If we've used all visitors, reset the list
        if not visitors:
            visitors = get_visitors()

        # Present the visitor and their request
        slow_print(f"\nA herald announces: \"{visitor.name}, {visitor.title}, seeks an audience!\"")
        time.sleep(0.5)
        slow_print(f"\n{visitor.name} approaches the throne and bows.")
        time.sleep(0.5)
        slow_print(f"\"{visitor.request}\"\n")
        time.sleep(0.5)

        # Present options
        slow_print("How do you respond?")
        for i, option in enumerate(visitor.options, 1):
            print(f"{i}. {option['text']}")

        # Get player choice
        valid_choice = False
        while not valid_choice:
            try:
                choice = int(input("\nYour decision (1-3): "))
                if 1 <= choice <= len(visitor.options):
                    valid_choice = True
                else:
                    print(f"Please enter a number between 1 and {len(visitor.options)}.")
            except ValueError:
                print("Please enter a valid number.")

        # Apply effects of choice
        selected_option = visitor.options[choice - 1]
        effects = selected_option['effects']

        slow_print(f"\n{selected_option['result']}")

        # Show effects
        effects_text = []
        if effects['happiness'] != 0:
            direction = "↑" if effects['happiness'] > 0 else "↓"
            effects_text.append(f"Happiness {direction} ({abs(effects['happiness'])})")

        if effects['treasury'] != 0:
            direction = "↑" if effects['treasury'] > 0 else "↓"
            effects_text.append(f"Treasury {direction} ({abs(effects['treasury'])} gold)")

        if effects['military'] != 0:
            direction = "↑" if effects['military'] > 0 else "↓"
            effects_text.append(f"Military {direction} ({abs(effects['military'])} soldiers)")

        if effects_text:
            slow_print("\nEffects: " + ", ".join(effects_text))

        # Update kingdom status
        kingdom.update_status(
            happiness_change=effects['happiness'],
            treasury_change=effects['treasury'],
            military_change=effects['military']
        )

        # Next turn
        if not kingdom.game_over:
            input("\nPress Enter to continue to the next day... ")
            kingdom.next_turn()

    # End game
    if not kingdom.game_over:
        # Player completed all 20 turns
        kingdom.display_status()
        slow_print("\nCongratulations! You have successfully ruled your kingdom for 20 years.")
        slow_print("Your reign will be remembered in the annals of history!")

        # Determine ending based on final status
        if kingdom.happiness >= 80:
            slow_print("\nYour subjects adore you! Bards sing of your benevolence and wisdom.")
        elif kingdom.happiness >= 50:
            slow_print("\nYour subjects generally approve of your rule, with some occasional grumbling.")
        else:
            slow_print("\nYour subjects tolerate your rule, though discontent simmers beneath the surface.")

        if kingdom.treasury >= 2000:
            slow_print("Your kingdom's coffers are overflowing with gold. Prosperity abounds!")
        elif kingdom.treasury >= 1000:
            slow_print("Your kingdom's finances are stable and healthy.")
        else:
            slow_print("Your kingdom's finances are stretched thin. Tax collectors work overtime.")

        if kingdom.military >= 1000:
            slow_print("Your mighty armies are the envy of neighboring realms. None dare threaten you.")
        elif kingdom.military >= 500:
            slow_print("Your military forces are adequate for defense of the realm.")
        else:
            slow_print("Your military is undermanned and underequipped, barely able to defend the borders.")

if __name__ == "__main__":
    main()
